  ('judicial-f0899a01-moex-00576', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '義務人對具行政處分性質之執行行為不服，於經過行政執行法第9條所定之聲明異議程序後，後續得提起 何種救濟？', '["提起再復審", "提起撤銷訴訟", "提起再異議", "提起再申訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00577', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於公法上金錢給付義務之行政執行，下列敘述何者錯誤？', '["基於比例原則現行法禁止藉由限制人身自由方式進行", "公法上金錢給付義務之執行名義可以經由法令規定形成", "對於公法上金錢給付義務之執行採取禁止重複查封原則", "逃漏稅之漏稅罰處分可以作為行政執行之執行名義"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00578', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於「處分機關未告知救濟期間或告知錯誤未為更正，致相對人或利害關係人遲誤者，如自處分書送達後 1年內聲明不服時，視為於法定期間內所為」之意涵敘述，下列何者錯誤？', '["在避免處分機關之違誤，造成未諳法律之人民，其訴訟權未獲確實保障", "以法律針對行政處分之救濟設有期間之限制為前提，所為救濟期間之寬限", "此規定亦適用於確認行政處分無效訴訟之提起", "旨在對於處分機關未告知救濟期間或告知錯誤未為更正，致相對人或利害關係人未能依法律規定時限提 起救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00579', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於政府資訊公開之敘述，下列何者錯誤？', '["對於外國人之資訊公開請求，採取互惠主義", "對於政府資訊公開之請求，原則上採取有償主義", "對於政府資訊公開之申請，有限制公開之例外", "就政府資訊公開之決定不服者，不得提起行政救濟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00580', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '有關聽證程序之敘述，下列何者正確？', '["行政機關訂定法規命令，得依職權舉行聽證", "不服聽證程序所作之行政處分，仍應提起訴願後，方可提起行政訴訟", "為維繫聽證程序順暢，故聽證程序之當事人不得對聽證主持人之處置聲明異議", "聽證程序貴在迅速，是以，不得進行再為聽證"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00581', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於主管機關核准都市更新事業程序中，正當行政程序要求之敘述，下列何者錯誤？', '["應確保利害關係人知悉相關資訊之可能性", "僅進行公聽程序已足", "允許利害關係人適時向主管機關以言詞或書面陳述意見", "行政處分通知書要遵守送達程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00582', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於訴願法上訴願程序之敘述，下列何者正確？', '["受理訴願機關均應經言詞辯論作成訴願決定", "訴願人對於受理訴願機關所為之程序處置不服者，得聲明異議", "訴願事件之行政處分經原處分機關撤銷者，受理訴願機關應以決定駁回之", "訴願有理由者，受理訴願機關得視事件之情節，作成逕為變更原行政處分之決定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00583', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '下列法律規定之行政救濟程序，何者屬訴願先行程序？', '["公務人員保障法之再申訴", "行政執行法之聲明異議", "政府採購法之異議", "教師法之再申訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
